public void processRequest(HttpServletRequest req) {
    String id = req.getParameter("id");

    // Tool flags this as SQL Injection:
    int userId = Integer.parseInt(id); // Throws NumberFormatException if not numeric!
    String query = "SELECT * FROM users WHERE id = " + userId;
    //                                                ^^^^^^^
    // SonarQube: BLOCKER - SQL Injection
    // But wait... userId is an INTEGER!
    // You cannot inject SQL through integer concatenation
    // parseInt() already validated the input is numeric
    // This is a FALSE POSITIVE

    // However, there IS a different vulnerability:
    // What if parseInt() throws NumberFormatException?
    // The exception might reveal the invalid input in error message
    // -> Information disclosure!

    // CORRECT triage:
    // SQL Injection warning: FALSE POSITIVE (integer type prevents injection)
    // Missing input validation: TRUE (should catch NumberFormatException)
}

// Proper code:
public void processRequestSecure(HttpServletRequest req) {
    try {
        int userId = Integer.parseInt(req.getParameter("id"));
        PreparedStatement ps = conn.prepareStatement(
            "SELECT * FROM users WHERE id = ?");
        ps.setInt(1, userId);
        // Both safe AND no false positive!
    } catch (NumberFormatException e) {
        resp.sendError(400, "Invalid user ID format");
    }
}

