#include <stdio.h>
#include <stdlib.h>
#include <string.h>

void parse_json(const char* input) {
    char key[64];   // Fixed-size buffer!
    char value[64];

    // Find key between quotes
    const char* start = strchr(input, '"');
    if (!start) return;
    start++;
    const char* end = strchr(start, '"');
    if (!end) return;

    // VULNERABLE: no length check!
    strncpy(key, start, end - start);  // Could overflow if key > 64 chars!
    key[end - start] = '\0';

    printf("Key: %s\n", key);
}

