public class MutationDemo {
    public static void main(String[] args) {
        String seed = "{\"age\": 25, \"name\": \"Alice\"}";
        System.out.println("Original seed: " + seed);
        System.out.println();

        // Mutation 1: Bit flip at position 8
        // Byte: '2' (0x32) -> flip bit 0 -> '3' (0x33)
        System.out.println("Mutation 1 (bit flip): {\"age\": 35, ...}");

        // Mutation 2: Replace with interesting value
        // 25 -> -1 (boundary value)
        System.out.println("Mutation 2 (interesting value): {\"age\": -1, ...}");

        // Mutation 3: Insert bytes
        // Insert 100 'A's into the name field
        System.out.println("Mutation 3 (insert): {\"age\": 25, \"name\": \"AAAA...100...\"}");

        // Mutation 4: Delete bytes
        // Remove the closing brace
        System.out.println("Mutation 4 (delete): {\"age\": 25, \"name\": \"Alice\"");

        // Mutation 5: Arithmetic on integer
        // 25 + MAX_INT
        System.out.println("Mutation 5 (arithmetic): {\"age\": 2147483672, ...}");

        // Mutation 6: Dictionary keyword
        // Insert SQL keyword
        System.out.println("Mutation 6 (dictionary): {\"age\": 25, \"name\": \"' OR 1=1--\"}");

        System.out.println();
        System.out.println("Each mutation explores different error handling!");
    }
}

